import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Separator, Avatar } from 'decantr/components';

code.example:
function ArticleContent() {
  const { div, h1, p, span, time, article: articleEl } = tags;
  const article = {
    title: 'Building Scalable Design Systems',
    author: { avatar: '', name: 'Jane Doe' },
    date: 'Mar 12, 2026',
    readTime: '8 min read',
    html: '<p>Design systems provide a shared language between design and engineering. By establishing reusable components and tokens, teams ship faster while maintaining consistency.</p>'
  };

  return articleEl({ class: css('_flex _col _gap6 _mw[720px] _mxa _py8') },
    div({ class: css('_flex _col _gap3') },
      h1({ class: css('_heading1') }, article.title),
      div({ class: css('_flex _aic _gap3') },
        Avatar({ src: article.author.avatar, name: article.author.name, size: 'sm' }),
        span({ class: css('_textsm') }, article.author.name),
        time({ class: css('_textsm _fgmuted') }, article.date),
        span({ class: css('_textsm _fgmuted') }, article.readTime)
      )
    ),
    Separator(),
    div({ class: css('_body _lhrelaxed'), innerHTML: article.html })
  );
}
